function n(){let e=document.getElementById("btn-scroll-top"),o=document.querySelector(".main-content");if(!e||!o)return;let t=()=>{o.scrollTop>300?e.classList.add("visible"):e.classList.remove("visible")};e.addEventListener("click",()=>{o.scrollTo({top:0,behavior:"smooth"})}),o.addEventListener("scroll",t,{passive:!0}),t()}document.addEventListener("DOMContentLoaded",n);export{n as initScrollToTop};
